// Lógica de llenado y automatización
document.addEventListener("DOMContentLoaded", function() {
    const selectMun = document.getElementById('dSolicitud');
    const inputOficina = document.getElementById('delegacion_display');
    const inputOficinaHidden = document.getElementById('delegacion_id');

    if (selectMun) {
        // 1. Ordenar municipios por nombre de la A a la Z
        municipiosMichoacan.sort((a, b) => a.nombre.localeCompare(b.nombre));

        // 2. Llenar el select
        municipiosMichoacan.forEach(mun => {
            let opt = document.createElement('option');
            opt.value = mun.id;
            opt.textContent = mun.nombre;
            opt.setAttribute('data-oficina', mun.delegacion);
            selectMun.appendChild(opt);
        });

        // 3. Evento de cambio
        selectMun.addEventListener('change', function() {
            const selected = this.options[this.selectedIndex];
            const oficina = selected.getAttribute('data-oficina') || "";
            
            if (inputOficina) inputOficina.value = oficina;
            if (inputOficinaHidden) inputOficinaHidden.value = oficina;
        });
    }
});